export interface TarotCardBase {
  id: number;
  image: string;
  name: string;
  korean: string;
  suit: string;
  keywords: string[];
  upright: string;
  reversedMeaning: string;
  love: string;
  career: string;
  money: string;
  short: string;
  // Universal Waite 심볼리즘
  element: string;
  numerology: string;
  symbolism: string;
  imageDescription: string;
  deepUpright: string;
  deepReversed: string;
  cardCombination: string;
}

export interface DeckCard extends TarotCardBase {
  isPicked: boolean;
  revealed: boolean;
  isReversed: boolean;
}

export function makeDeckCard(card: TarotCardBase, isPicked: boolean, revealed: boolean, isReversed: boolean): DeckCard {
  return { ...card, isPicked, revealed, isReversed };
}

